import SettingsBase from "./SettingsBase.js"


export default class AppSettingsHandler extends SettingsBase {

    constructor() {
        super()
        this._recordType = 'app-settings'
    }

    async getAppSettings() {
        return await this._getOrCreateSettings()
    }

    async setIsAutoTrim(value) {
        let appSettings = await this.getAppSettings()
        appSettings.isAutoTrim = value
        this.saveSettings(appSettings)
    }

    async setRecordingsToKeep(value) {
        let appSettings = await this.getAppSettings()
        appSettings.recordingsToKeep = value
        this.saveSettings(appSettings)
    }
    async setTabTitleAsName(value) {
        let appSettings = await this.getAppSettings()
        appSettings.useTabTitleAsName = value
        this.saveSettings(appSettings)
    }
}