import Config from '../../config.js'

export default class Recorder {
  constructor(port, recordingConfig) {
    this.CONFIG = new Config();
    this.stream = null;
    this.recordingConfig = recordingConfig;
    this.audioContext = null;
    this.tabAudioInput
    this._initWorker();
  }

  async startRecording() {
    this.audioContext = new AudioContext({sampleRate: this.recordingConfig.sampleRate});
    await this._initRecorderNode()
    this.tabAudioInput = await this._getTabInputNode()
    this.tabAudioInput.connect(this.recorderNode);
    this.recorderNode.connect(this.audioContext.destination);
    this._startRecorderWorklet();
    this.recordingStartTime = Date.now()
    return true;
   }

   async stopRecording() {
    if (this.recorderNode) {
      this._stopRecorderWorklet()
    }
    if (this.stream) {
      this.stream.getAudioTracks()[0].stop();
    }
   }

   async encodeWhole(data, encodingType, recordingID) {
    this.worker.postMessage({"command": "init", "config": this.recordingConfig})
    this.worker.postMessage({"command":"encodeWhole", 
                             "buffer": data, 
                             "bufferSize": data[0].length,
                             "encodingType": encodingType,
                             "recordingID": recordingID})
  }

  async refreshRecordingConfig(newConfig) {
    this.recordingConfig = newConfig
    this.worker.postMessage({"command": "init", "config": this.recordingConfig})
  }

  _initWorker() {
      this.worker = new Worker('./recorderMessagesWorker.js', { type: 'module' });
      this.worker.onmessage = (event) => {
          let data = event.data;
          switch (data.command) {
            case "progress": this._measureTime(); break;
            case "recordingComplete": this.onComplete(data.audioData); break;
            case "encodingFinished": this.handleOfflineEncoding(data.audioData, data.encodingType, data.recordingID); break;
          }
      }
      this.worker.postMessage({"command": "init", "config": this.recordingConfig})
    }

  _stopRecorderWorklet() {
      let isRecording = this.recorderNode.parameters.get('isRecording')
      isRecording.setValueAtTime(0, this.audioContext.currentTime);
  }
      

  _startRecorderWorklet() {
    let isRecording = this.recorderNode.parameters.get('isRecording')
    isRecording.setValueAtTime(1, this.audioContext.currentTime);
  }

  async _getTabInputNode() {
    this.stream = await chrome.tabCapture.capture(this.CONFIG.CAPTURE_PROPERTIES)
    this.audioContext.createMediaStreamSource(this.stream).connect(this.audioContext.destination)
    var input = this.audioContext.createMediaStreamSource(this.stream);
    return input
  }

  async _initRecorderNode() {
    await this.audioContext.audioWorklet.addModule(this.CONFIG.RECORDING_PROPERTIES.recorderWorkletPath)
    this.recorderNode = new window.AudioWorkletNode(this.audioContext, 'recorder-worklet', {parameterData: 
                                                    {numberOfChannels: this.recordingConfig.numChannels,
                                                     channelsToRecord: this.recordingConfig.channelsToRecord,
                                                      }
                                                    });
    this._handleRecorderNodeEvents()
  }

  _handleRecorderNodeEvents() {
    this.recorderNode.port.onmessage = (event) => {
      var data = event.data
      switch(data.eventType) {
        case "data": this.worker.postMessage({"command": "record", "buffer": data.audioBuffer, "bufferSize": data.bufferSize}); break;
        case "stop": this.worker.postMessage({"command": "finish"}); break;
        } 
      }    
  }

  _measureTime() {
    let now = Date.now()
    if ((now - this.recordingStartTime) / 1000 > this.recordingConfig.timeLimit) {
      this.stopRecording();
    }
  }
}
