import Config from './config.js'
import Recorder from './lib/recorder/recorder.js'
import StateHandler from './lib/database/StateHandler.js'
import AppSettingsHandler from './lib/database/settings-db/AppSettingsHandler.js'
import RecordingsHandler from './lib/database/RecordingsHandler.js'
import RecordingSettingsHandler from './lib/database/settings-db/RecordingSettingsHandler.js'
import {newsData} from './news.js'
import { nanoid } from 'nanoid'

import 'chrome-extension-async';


let wasRegistered = false;
const CONFIG = new Config();
var port;
var recorder;
var stateDataHandler;
var recordingsDataHandler;
var activeSampleData = {}
var showNewsNotification;
var appSettings;
var appSettingsDataHandler;
var recordingSettings;
var recordingSettingsDataHandler;
var state;

browser.runtime.onStartup.addListener( () => {
  initBackground(true)
})


browser.runtime.onInstalled.addListener( () => {
  initBackground(true)
})

browser.runtime.onConnect.addListener( (portDeclaration) => {
  port = portDeclaration;
  port.onMessage.addListener( async (event) => {
    switch(event.message) {
      case "init":
        await initBackground(false);
        break;
      case "start-recording":
        await handleStartRecording()
        if (state.recordingInProgress === true) {
          port.postMessage({"message": "recording-in-progress"})
        }
        break;
      case "stop-recording":
        handleStopRecording()
        break;
      case "load-recent-recordings":
        var recentRecordings = await recordingsDataHandler.getRecentRecordings()
        port.postMessage({"message": "recent-recordings-ready", "data": recentRecordings})
        break;
      case "delete-recording":
        if (event.data.id == activeSampleData.id) {
          _handleDeleteActiveSample()
          port.postMessage({"message": "active-recording-deleted"})
        }
        recordingsDataHandler.deleteRecording(event.data.id)
        break;
      case 'load-new-recording':
        await activateNewRecording(event.id)
        break;
      case 'refresh-url':
        activeSampleData.path = await getNewURL(event.data.id)
        port.postMessage({"message": "new-url-ready", "url": activeSampleData.path })
        break;
      case 'sample-time-data':
        recordingsDataHandler.updateTimeData(event.data.id, event.data.start, event.data.length)
        activeSampleData.start = event.data.start
        activeSampleData.length = event.data.length
        break;
      case 'new-name':
        var name =  event.data.name.substring(0, 30)
        recordingsDataHandler.updateName(event.data.id, name)
        activeSampleData.name = name
        break;
      case 'download-recording':
        prepareSampleDownload(event.data.id)
        break;
      case 'generate-reversed-audio':
        prepareReversedSample();
        break;
      case 'looping-state-status':
        state.isLooping = event.data.isLooping
        stateDataHandler.setIsLooping(event.data.isLooping)
        break;
      case 'news-viewed':
        await stateDataHandler.setNewsVersion(state.currentNewsVersion)
        port.postMessage({"message": "remove-news-notification"})
        handleExtensionIcon()
        break;
      case 'load-settings':
        var settings = new Object()
        settings.recordingSettings = recordingSettings
        settings.appSettings = appSettings
        port.postMessage({"message": "settings-ready", "data": settings})
        break;
      case 'new-recorded-channels':
        updateRecordingSettings('recorded-channels',  event.data.value)
        break;
      case 'new-sample-rate':
        updateRecordingSettings('sample-rate',  event.data.value)
        break;
      case 'new-recordings-to-keep-amount':
        var recordingsToKeep = parseInt(event.data.value)
        if (recordingsToKeep < 0)
          recordingsToKeep = 0
        if (recordingsToKeep > 30)
          recordingsToKeep = 30
        appSettings.recordingsToKeep = recordingsToKeep
        appSettingsDataHandler.setRecordingsToKeep(recordingsToKeep)
        break;
      case 'auto-trim-setting':
        appSettings.isAutoTrim = event.data.value
        appSettingsDataHandler.setIsAutoTrim(event.data.value)
        break;
      case 'update-recording-format':
        updateRecordingSettings('recording-format',  event.data.value)
        break;
      case 'update-tab-title-as-name':
        updateAppSettings('tab-title-as-name',  event.data.value)
        break;
    }
  })
})

const initBackground = async (silentMode) => {
  if (!wasRegistered) {
    await initDB()
    await handleRecordingSettings();
    await handleAppSettings();
    await handleState();
    handleExtensionIcon()
    initRecorder()
    wasRegistered = true
  }
  if (!activeSampleData.path && !activeSampleData.id && !state.isRecordingMode) {
      await _loadMostRecentSample()
  }
  showNewsNotification = await shouldDisplayNewNotification();

  if (silentMode === false) {
    let data = {"message": "init-complete", 
              "recording_in_progress": state.recordingInProgress, 
              "is_looping": state.isLooping,
              "is_auto_trim":  appSettings.isAutoTrim ,
              "sample_data": activeSampleData,
              "state": state,
              "waveform_options": CONFIG.WAVEFORM_PROPERTIES,
              "news": newsData,
              "show_news_notification": showNewsNotification,
            }
    port.postMessage(data)
  }
}

const _loadMostRecentSample = async () => {
  let recentRecording = await recordingsDataHandler.getMostRecentRecording()
  if (recentRecording) {

    let audioData = recentRecording._attachments.recording.data
    let blob = await base64ToBlob(audioData)
    activeSampleData.path = window.URL.createObjectURL(blob);
    activeSampleData.id = recentRecording._id
    activeSampleData.start = recentRecording.start
    activeSampleData.length = recentRecording.length
    activeSampleData.originalDuration = recentRecording.originalDuration
    activeSampleData.name = recentRecording.name
    activeSampleData.blob = blob
    activeSampleData.isReversed = recentRecording.isReversed
  }
}

const handleStartRecording = async () => {
  activeSampleData = {}
  if (state.recordingInProgress != true) {
    let recordingStarted = await recorder.startRecording()
    if (recordingStarted === true) {
      if (appSettings.useTabTitleAsName) {
        const [tab] = await chrome.tabs.query( { active: true, currentWindow: true });
        activeSampleData.name = tab.title.substring(0, 30)
      }
      else {
        activeSampleData.name =  `recording-${getPrettyDatetime(new Date())}`
      }
      
      state.recordingInProgress = recordingStarted;
      stateDataHandler.setIsRecording(state.recordingInProgress);
    }
  }
}

const handleStopRecording = async () => {
  state.recordingInProgress = false
  stateDataHandler.setIsRecording(state.recordingInProgress);
  recorder.stopRecording()
}

const storeRecording = async (blob) => {
  let now =  new Date();
  let sampleDuration = await _getSampleDuration(blob)
  let recordingID = `recording-${nanoid(10)}`

  activeSampleData.path = window.URL.createObjectURL(blob);
  activeSampleData.blob = blob
  activeSampleData.length = _getSampleLength(sampleDuration)
  activeSampleData.originalDuration = sampleDuration
  activeSampleData.start = _getSampleStart(sampleDuration)
  activeSampleData.isReversed = false
  activeSampleData.id = recordingID
  recordingsDataHandler.createNewRecordingRecord(recordingID,
                                                  blob, 
                                                  activeSampleData.path,
                                                  activeSampleData.length,
                                                  activeSampleData.start,
                                                  activeSampleData.name,
                                                  appSettings.recordingsToKeep,
                                                  recordingSettings.recordingFormat,
                                                  );
  state.isRecordingMode = false;
  const data = {'message': 'recording-finished', 
                'sample_data': activeSampleData
                };
  port.postMessage(data)
}

const _getSampleStart = (sampleDuration) => {
  if (appSettings.isAutoTrim){
    return sampleDuration / 10
  }
  return 0
}

const _getSampleLength = (sampleDuration) => {
  if (appSettings.isAutoTrim) { 
    return sampleDuration - (sampleDuration / 5)
  }
    return  sampleDuration 
}

const _getSampleDuration = async (blob) => {
  let audioArray = await blob.arrayBuffer()
  let ctx = new window.AudioContext({sampleRate: recordingSettings.sampleRate});
  let audioData = await ctx.decodeAudioData(audioArray)
  return audioData.duration
}


const base64ToBlob = async (base64Blob) => {
  let base64Response = await fetch(`data:audio/wave;base64,${base64Blob}`);
  let blob = await base64Response.blob();
  return blob
}


const initRecorder = () => {
  if (!recorder) {
    recorder = new Recorder(port, recordingSettings)
    recorder.onComplete = function(blob) {storeRecording(blob)}
    recorder.handleOfflineEncoding = function(blob, encodingType, recordingID) {handleOfflineEncoding(blob, encodingType, recordingID)}
  }
}

const initDB = async () => {
  if (!recordingsDataHandler) {
    recordingsDataHandler = new RecordingsHandler()
  }
  if (!stateDataHandler) {
    stateDataHandler = new StateHandler()
  }
  if (!appSettingsDataHandler) {
    appSettingsDataHandler = new AppSettingsHandler()
  }
  if (!recordingSettingsDataHandler) {
    recordingSettingsDataHandler = new RecordingSettingsHandler()
  }

  await recordingsDataHandler.RefreshAllDataURLs()
}

const _handleDeleteActiveSample = async () => {
  activeSampleData.id = undefined
  activeSampleData.path = undefined
  state.isRecordingMode = true
}

const activateNewRecording = async (id) => {
  let recording = await recordingsDataHandler.getRecordingByID(id);
  recordingsDataHandler.updateRecordingAccessTime(id)
  activeSampleData.path = recording.dataURL
  activeSampleData.id = id
  activeSampleData.start = recording.start
  activeSampleData.length = recording.length
  activeSampleData.originalDuration = recording.originalDuration
  activeSampleData.name = recording.name
  port.postMessage({"message": "new-recording-loaded", "sample_data": activeSampleData})
}

const getNewURL = async (id) => {
  let newURL = await recordingsDataHandler.refreshDataURL(id);
  return newURL
  
}

const handleOfflineEncoding = async (blob, encodingType, recordingID) => {
  if (encodingType == "reverse") {
    proceedToReverse(blob)
  }
  if (encodingType == "download") {
    proceedToDownload(blob, recordingID)
  }
}

const proceedToReverse = (blob) => {
  activeSampleData.blob = blob
  activeSampleData.path = URL.createObjectURL(blob);
  activeSampleData.isReversed = !activeSampleData.isReversed
  recordingsDataHandler.updateReverseData(activeSampleData.id, blob, activeSampleData.path, activeSampleData.isReversed)
  port.postMessage({"message": "reverse-recording-ready", "sample_data": activeSampleData})
}

const getSampleData = async (id) => {
  let sampleData;
  if (id == activeSampleData.id) {
    sampleData = activeSampleData
  }
  else {
    sampleData = await recordingsDataHandler.getRecordingData(id)
  }
  return sampleData
}

const prepareSampleDownload = async (id) => {
  port.postMessage({"message": "encoding-started", "startTime": Date.now()})
  let sampleData = await getSampleData(id)
  let audioArray = await sampleData.blob.arrayBuffer()
  let audioCtx = new window.AudioContext({sampleRate: recordingSettings.sampleRate});
  let sourceBuffer = await audioCtx.decodeAudioData(audioArray)
  let sampleRate = recordingSettings.sampleRate
  let numChannels =  recordingSettings.numChannels
  let offlineCtx = new OfflineAudioContext(numChannels, sampleRate * sampleData.length, sampleRate);
  let source = offlineCtx.createBufferSource();
  source.buffer = sourceBuffer;
  source.connect(offlineCtx.destination);
  source.start(0, sampleData.start, sampleData.length);
  let renderedBuffer = await offlineCtx.startRendering();
  let byChannelBuffer = [];
  for (let ch = 0; ch < numChannels; ++ch) {
    byChannelBuffer[ch] = renderedBuffer.getChannelData(ch);
  }
  recorder.encodeWhole(byChannelBuffer, "download", sampleData.id)
}

const proceedToDownload = async (blob, recordingID) => {
    let sampleData = await getSampleData(recordingID)
      const blobUrl = URL.createObjectURL(blob);
      const a = document.createElement('a');
      document.body.appendChild(a);
      a.style = 'display: none';
      a.href = blobUrl;
      a.download = `${sampleData.name}.${recordingSettings.recordingFormat}`
      a.click();
      URL.revokeObjectURL(blobUrl); 
      port.postMessage({"message": "encoding-finished"})
}

const prepareReversedSample = async () => {
  port.postMessage({"message": "reverse-started", "startTime": Date.now()})
  let audioArray = await activeSampleData.blob.arrayBuffer()
  let ctx = new window.AudioContext({sampleRate: recordingSettings.sampleRate});
  let audioData = await ctx.decodeAudioData(audioArray)
  let byChannelBuffer = [];
  for (let ch = 0; ch < audioData.numberOfChannels; ++ch) {
    byChannelBuffer[ch] = Array.prototype.reverse.call(audioData.getChannelData(ch))
  }
  recorder.encodeWhole(byChannelBuffer, "reverse")
}

const getPrettyDatetime = (datetime) => {
  let hours = getPrettyTime(datetime.getHours())
  let minutes = getPrettyTime(datetime.getMinutes())
  let seconds = getPrettyTime(datetime.getSeconds())

  let prettyDate = datetime.getDate()+'-'+(datetime.getMonth()+1)+'-'+datetime.getFullYear();
  let prettyTime = hours + ":" + minutes + ":" + seconds;
  return prettyDate+' '+prettyTime;
}

const getPrettyTime = (time) => {
  if (time < 10) {
    return `0${time}`
  }
  return time

}

const shouldDisplayNewNotification = async () => {
  let newsVersionInDB = await stateDataHandler.getNewsVersion()
  if (state.currentNewsVersion != newsVersionInDB) {
    return true;
  }
  return false;
}

const handleExtensionIcon = async () => {
  const showNewsNotification = await shouldDisplayNewNotification();
  if (showNewsNotification === true) {
    chrome.browserAction.setBadgeText({text: "1"});
    chrome.browserAction.setBadgeBackgroundColor({ color: "#e8ae00" })
  }
  else {
    chrome.browserAction.setBadgeText({text: null});
  }
}

const handleRecordingSettings = async () => {
  recordingSettings = await recordingSettingsDataHandler.getRecordingSettings()
  if (!recordingSettingsDataHandler.hasData(recordingSettings)) {
    recordingSettings.sampleRate = CONFIG.RECORDING_PROPERTIES.sampleRate
    recordingSettings.numChannels = CONFIG.RECORDING_PROPERTIES.numChannels
    recordingSettings.timeLimit = CONFIG.RECORDING_PROPERTIES.timeLimit
    recordingSettings.channelsToRecord = CONFIG.RECORDING_PROPERTIES.channelsToRecord
    recordingSettings.recordingFormat = CONFIG.RECORDING_PROPERTIES.recordingFormat
  }
  recordingSettingsDataHandler.saveSettings(recordingSettings)
}

const handleAppSettings = async () => {
  appSettings = await appSettingsDataHandler.getAppSettings()
  if (!appSettingsDataHandler.hasData(appSettings)) {
    appSettings.isAutoTrim = true;
    appSettings.recordingsToKeep = CONFIG.APP_PROPERTIES.recordingsToKeep
    appSettings.useTabTitleAsName = false
  }
  appSettingsDataHandler.saveSettings(appSettings)
}

const handleState = async () => {
  state = await stateDataHandler.getState()
  if (!stateDataHandler.hasData(state)) {
    state.recordingInProgress = false
    state.isLooping = false
    state.isRecordingMode = true
  }
  state.currentNewsVersion = newsData[0].version
  stateDataHandler.saveState()

}

const updateRecordingSettings = async(prop, value) => {
  switch(prop) {
    case 'recorded-channels':
      recordingSettings.channelsToRecord = value
      recordingSettingsDataHandler.setChannelsToRecord(recordingSettings.channelsToRecord)
      break;
    case 'sample-rate':
      recordingSettings.sampleRate = value
      recordingSettingsDataHandler.setSampleRate(recordingSettings.sampleRate)
      break
    case 'recording-format':
      recordingSettings.recordingFormat = value
      recordingSettingsDataHandler.setRecordingFormat(recordingSettings.recordingFormat)
      break
  }
  recorder.refreshRecordingConfig(recordingSettings)
}

const updateAppSettings = async(prop, value) => {
  switch(prop) {
    case 'tab-title-as-name':
      appSettings.useTabTitleAsName = value
      appSettingsDataHandler.setTabTitleAsName(appSettings.useTabTitleAsName)
      break;
  }
}
