import SettingsBase from "./SettingsBase.js"


export default class RecordingSettingsHandler extends SettingsBase {

    constructor() {
        super()
        this._recordType = 'recording-settings'
    }

    async getRecordingSettings() {
        return await this._getOrCreateSettings()
    }

    async setChannelsToRecord(value) {
        let recordingSettings = await this.getRecordingSettings()
        recordingSettings.channelsToRecord = value
        this.saveSettings(recordingSettings)
    }

    async setSampleRate(value) {
        let recordingSettings = await this.getRecordingSettings()
        recordingSettings.sampleRate = value
        this.saveSettings(recordingSettings)
    }

    async setRecordingFormat(value) {
        let recordingSettings = await this.getRecordingSettings()
        recordingSettings.recordingFormat = value
        this.saveSettings(recordingSettings)
    }
}
