import PouchDB from "pouchdb"
import {isEmpty} from '../../../utils/CommonUtils'


export default class SettingsBase {
  constructor() {
    this._settingsDB = new PouchDB('settings')
    this._recordType = undefined
  }

  async _getOrCreateSettings() {
    let settings = {}
    settings = await this._getSettings()

    if (isEmpty(settings)) {
        await this._createSettings()
        settings = await this._getSettings()
    }
    return settings
  }

  async _getSettings() {
    if (this._recordType) {
      let settings;
      try {
        settings = await this._settingsDB.get(this._recordType)
      }
      catch (error) {
        settings = {}
      }
      return settings
    }
  }

  async _createSettings() {
    if (this._recordType) {
      await this._settingsDB.put({_id: this._recordType})
    }
  }

  async saveSettings(record) {
    this._settingsDB.put(record)
  }

  hasData(record) {
    if (Object.keys(record).length > 2) {
      return true
    }
    return false
  }

}

