import PouchDB from "pouchdb"
import {isEmpty} from '../../utils/CommonUtils'


export default class StateHandler {
  constructor() {
    this._stateDB = new PouchDB('state')
  }


  async getState() {
    return await this._getOrCreateState()
  }

  async _getOrCreateState() {
    let state = {}
    state = await this._getStateRecord()
    if (isEmpty(state)) {
        await this._createState()
        state = await this._getStateRecord()
    }
    return state
  }

  async _getStateRecord() {
    let state;
    try {
      state = await this._stateDB.get('state')
    }
    catch (error) {
      state = {}
    }
    return state
  }

  async _createState() {
    await this._stateDB.put({_id: "state"})
  }

  async setIsRecording(isRecording) {
    let state = await this.getState()
    state.recordingInProgress = isRecording
    this._stateDB.put(state)
  }

  async setIsReversed(isReversed) {
    let state = await this.getState()
    state.isReversed = isReversed
    this._stateDB.put(state)
  }

  async setIsLooping(isLooping) {
    let state =  await this.getState()
    state.isLooping = isLooping
    this._stateDB.put(state)
  }

  async getIsRecording() {
    let state = await this.getState()
    return state.isRecording
  }

  async getIsReversed() {
    let state = await this.getState()
    return state.isReversed
  }

  async getIsLooping() {
    let state = await this.getState()
    return state.isLooping
  }

  async getNewsVersion() {
    let state = await this.getState()
    return state.currentNewsVersion;
  }

  async setNewsVersion(version) {
    let state = await this.getState()
    state.currentNewsVersion = version;
    this._stateDB.put(state)
  }

  async setIsRecordingMode(value) {
    let state = await this.getState()
    state.isRecordingMode = value;
    this._stateDB.put(state)
  }

  hasData(record) {
    if (Object.keys(record).length > 2) {
      return true
    }
    return false
  }

  async saveState(record) {
    this._stateDB.put(record)
  }

}