import PouchDB from 'pouchdb'
import PouchDBFind from 'pouchdb-find'

PouchDB.plugin(PouchDBFind)

export default class RecordingsHandler {
  constructor() {
    this._recordingsDB = new PouchDB('recordings')
    
}

async setRecordingName(recordingID, name) {
  let recording = await this._recordingsDB.get(recordingID)
  recording.name = name
  this._recordingsDB.put(recording)
}


async getMostRecentRecording() {
  let totalRows = await this._getTotalRecords()
  if (totalRows > 0) {
    let mostRecentID = await this._getMostRecentRecordingID()
    let recordingData = await this._recordingsDB.get(mostRecentID, {attachments: true})
    this.updateRecordingAccessTime(mostRecentID)
    return recordingData
  }
}

async getRecentRecordings() {
  let allRecordings = []
  let all = await this._recordingsDB.allDocs({include_docs: true, attachments: false})
  all.rows.forEach(row => {
    if (row.id.includes("recording-")) {
      allRecordings.push(row.doc)
    }
  })
  allRecordings.sort( (a, b) => {
    return b.lastAccessTime - a.lastAccessTime 
  })
  return allRecordings

  }

async RefreshAllDataURLs() {
  let all = await this._recordingsDB.allDocs({include_docs: true, attachments: true})
  all.rows.forEach(async (row) => {
    if (row.id.includes("recording-")) {
      let dataURL = await this._getDataURL(row.doc)
      row.doc.dataURL = dataURL
      this._recordingsDB.put(row.doc)
    }
  })
}

async _getDataURL(doc) {
  let data = doc._attachments.recording.data
  let blob = await this._base64ToBlob(data)
  return URL.createObjectURL(blob)
}

async _base64ToBlob(base64Blob) {
  let base64Response = await fetch(`data:audio/wave;base64,${base64Blob}`);
  let blob = await base64Response.blob();
  return blob
}


async _getMostRecentRecordingID() {
  await this._recordingsDB.createIndex({index: {fields: ["lastAccessTime"]}})
  let recordings = await this._recordingsDB.find({
    selector: {
      $and: [
        {_id: {$exists: true}},
        {lastAccessTime: {$gt: true}}
       ]
    },
    sort: [{"lastAccessTime": "desc"}], 
    limit: 1,
    fields: ["_id"]
  })
  let mostRecentRecording = recordings.docs[0]
  if (mostRecentRecording) {
    return mostRecentRecording._id
  }
}

async _getOldestRecordingID() {
  await this._recordingsDB.createIndex({index: {fields: ["lastAccessTime"]}})
  let recordings = await this._recordingsDB.find({
    selector: {
      $and: [
        {_id: {$exists: true}},
        {lastAccessTime: {$gt: true}}
       ]
    },
    sort: [{"lastAccessTime": "asc"}], 
    limit: 1,
    fields: ["_id"]
  })
  let mostRecentRecording = recordings.docs[0]
  if (mostRecentRecording) {
    return mostRecentRecording._id
  }
}


async createNewRecordingRecord(recordingID, blob, url, length, start, name, recordsToKeep, encodingFormat) {
  let nowUseful = Date.now()
  let encodingFormatFormatReadable = (encodingFormat == 'wav') ? 'wave' : 'mp3'
  await this._recordingsDB.put({_id: recordingID, 
                           recordingTime: nowUseful, 
                           lastAccessTime: nowUseful,
                           name: name,
                           dataURL: url,
                           length: length,
                           originalDuration: length,
                           isReversed: false,
                           start: start,
                           encodingFormat: encodingFormat,
                           _attachments: {
                            'recording': {
                              content_type: `audio/${encodingFormatFormatReadable}`,
                              data: blob
                            }
                          }
  })
  this.handleExcessiveRecordings(recordsToKeep)
  return recordingID
  }

async handleExcessiveRecordings(recordsToKeep) {
  let totalRecords = await this._getTotalRecords() 
  if (totalRecords > recordsToKeep) {
    let oldestRecordingID = await this._getOldestRecordingID()
    await this.deleteRecording(oldestRecordingID)
  }
}

async deleteRecording(recordingID) {
  let recording = await this._recordingsDB.get(recordingID)
  this._recordingsDB.remove(recording)
}

async updateRecordingAccessTime(recordingID) {
  let recording = await this._recordingsDB.get(recordingID)
  recording.lastAccessTime = Date.now()
  this._recordingsDB.put(recording)
}

async _getTotalRecords() {
  var total = 0
  let all = await this._recordingsDB.allDocs()
  all.rows.forEach(doc => {
    if (doc.id.includes("recording-")) {
      total += 1
    }
  })
  return total
}



async getRecordingByID(id, attachments_flag) {
  let recordingData = await this._recordingsDB.get(id, {attachments: attachments_flag})
  return recordingData
}

async refreshDataURL(id) {
  let recordingData = await this.getRecordingByID(id, true)
  let dataURL = await this._getDataURL(recordingData)
  recordingData.dataURL = dataURL
  this._recordingsDB.put(recordingData)
  return dataURL
}

async updateTimeData(id, sampleStart, sampleLength) {
  let recordingData = await this.getRecordingByID(id, false)
  recordingData.start = sampleStart
  recordingData.length = sampleLength
  this._recordingsDB.put(recordingData)
}

async updateName(id, name) {
  if (name) {
    let recordingData = await this.getRecordingByID(id, false)
    recordingData.name = name
    this._recordingsDB.put(recordingData)
  }
}

async getRecordingData(id) {
  let recordingData = await this.getRecordingByID(id, true)
  let data = {blob: await this._base64ToBlob(recordingData._attachments.recording.data),
              start: recordingData.start,
              length: recordingData.length,
              name: recordingData.name,
              isReversed: recordingData.isReversed,
              id: recordingData._id,
  }
  return data
}

async updateReverseData(id, blob, url, isReversed) {
  let recordingData = await this.getRecordingByID(id, true)
  recordingData.dataURL = url
  recordingData._attachments = {
    'recording': {
      content_type: 'audio/wave',
      data: blob
    }
  }
  recordingData.isReversed = isReversed
  this._recordingsDB.put(recordingData)
}


}